() => {
  function getXPath(el) {
    if (!el) return null;
    if (el.id) return '//*[@id="' + el.id + '"]';

    const parts = [];
    while (el && el.nodeType === Node.ELEMENT_NODE) {
      let index = 1;
      let sibling = el.previousElementSibling;

      while (sibling) {
        if (sibling.nodeName === el.nodeName) index++;
        sibling = sibling.previousElementSibling;
      }

      parts.unshift(el.nodeName.toLowerCase() + "[" + index + "]");
      el = el.parentElement;
    }

    return "/" + parts.join("/");
  }

  const products = [];
  const articles = document.querySelectorAll('article.product_pod');

  for (let i = 0; i < Math.min(10, articles.length); i++) {
    const article = articles[i];

    // Get title link element
    const titleLink = article.querySelector('h3 a');
    const imageLink = article.querySelector('.image_container a');

    // Get name
    const name = titleLink ? titleLink.getAttribute('title') : null;

    // Get product URL
    const relativeUrl = titleLink ? titleLink.getAttribute('href') : null;
    const productUrl = relativeUrl ? new URL(relativeUrl, 'https://books.toscrape.com/catalogue/').href : null;

    // Get price
    const priceElement = article.querySelector('.price_color');
    const price = priceElement ? priceElement.textContent.trim() : null;

    // Get rating
    const ratingElement = article.querySelector('.star-rating');
    let rating = null;
    if (ratingElement) {
      const ratingClass = ratingElement.className;
      if (ratingClass.includes('One')) rating = '1';
      else if (ratingClass.includes('Two')) rating = '2';
      else if (ratingClass.includes('Three')) rating = '3';
      else if (ratingClass.includes('Four')) rating = '4';
      else if (ratingClass.includes('Five')) rating = '5';
    }

    // Get availability
    const availElement = article.querySelector('.availability');
    let availability = null;
    if (availElement) {
      const availText = availElement.textContent.trim();
      if (availText.includes('In stock')) {
        availability = 'In stock';
      } else if (availText.includes('Out of stock')) {
        availability = 'Out of stock';
      }
    }

    // Get XPath of title link
    const sourceXpath = titleLink ? getXPath(titleLink) : null;

    products.push({
      record_id: String(i + 1),
      name: name,
      price: price,
      rating: rating,
      availability: availability,
      product_url: productUrl,
      source_url: 'https://books.toscrape.com/',
      source_xpath: sourceXpath
    });
  }

  return products;
}
